async function execute(browser, params) {
    const navLink = await browser.extractComponent(
        {
            typeName: 'NavigationLink',
            schema: '{ title: string; linkSelector: string; }'
        },
        params.keywords
    );
    if (!navLink || !navLink.linkSelector) {
        throw new Error('Could not find navigation link matching: ' + params.keywords);
    }
    await browser.click(navLink.linkSelector);
    await browser.awaitPageLoad();
    return { success: true, message: 'Navigated to ' + navLink.title };
}
